package ra.edu.shoesphere.model.entity; import jakarta.persistence.*; import lombok.*; import ra.edu.shoesphere.model.entity.enums.OrderStatus; import java.math.*; import java.time.*;
@Entity @Table(name="orders") @Getter @Setter @NoArgsConstructor public class Order { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne private User user; private String receiverName; private String receiverPhone; private String deliveryAddress; private BigDecimal totalAmount; @Enumerated(EnumType.STRING) private OrderStatus status; private LocalDateTime createdAt; @PrePersist void create(){createdAt=LocalDateTime.now();} }
